import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { profileAPI, mentorsAPI, quizAPI } from '../../services/api';
import './Progress.css';

const Progress = () => {
  const [progress, setProgress] = useState({
    quizCompleted: 0,
    profileCompleted: 0,
    skillsAdded: 0,
    mentorsConnected: 0,
    coursesEnrolled: 0
  });
  const [quizResults, setQuizResults] = useState(null);
  const [loading, setLoading] = useState(true);
  const [lastUpdated, setLastUpdated] = useState(null);
  const { user } = useAuth();

  useEffect(() => {
    fetchProgress();
  }, [user]);

  const fetchProgress = async () => {
    try {
      setLoading(true);
      
      const [profileResponse, mentorResponse, quizResponse] = await Promise.allSettled([
        profileAPI.getProfile(),
        mentorsAPI.getMyRequests(),
        quizAPI.getHistory()
      ]);

      // Reset quiz completion to 0 for new users
      let quizCompleted = 0;
      let quizData = null;

      // STRICT quiz completion check - only mark as complete if user actually took the quiz
      if (quizResponse.status === 'fulfilled' && quizResponse.value.success) {
        const quizHistory = quizResponse.value.history || [];
        if (quizHistory.length > 0) {
          const latestQuiz = quizHistory[0];
          if (latestQuiz.results && latestQuiz.results.personalityType) {
            quizData = latestQuiz.results;
            quizCompleted = 100;
          }
        }
      }

      // Check localStorage as backup
      if (!quizData) {
        const localQuizResults = localStorage.getItem('last_quiz_results');
        if (localQuizResults) {
          try {
            const parsedResults = JSON.parse(localQuizResults);
            if (parsedResults.personalityType) {
              quizData = parsedResults;
              quizCompleted = 100;
            }
          } catch (e) {
            // Invalid data, keep quiz as incomplete
          }
        }
      }

      // Profile completion
      const profileData = await getProfileData(profileResponse, user);
      const profileCompleted = calculateProfileCompletion(profileData);
      const skillsAdded = calculateSkillsProgress(profileData.skills || []);

      // Mentor connections
      const mentorsConnected = await checkMentorConnections(mentorResponse);

      setQuizResults(quizData);
      setProgress({
        quizCompleted,
        profileCompleted,
        skillsAdded,
        mentorsConnected,
        coursesEnrolled: 0
      });
      setLastUpdated(new Date());
      
    } catch (error) {
      console.error('Error fetching progress:', error);
      // Set all to 0 for new users
      setProgress({
        quizCompleted: 0,
        profileCompleted: 0,
        skillsAdded: 0,
        mentorsConnected: 0,
        coursesEnrolled: 0
      });
    } finally {
      setLoading(false);
    }
  };

  const getProfileData = async (profileResponse, userData) => {
    if (profileResponse.status === 'fulfilled' && profileResponse.value?.user) {
      return profileResponse.value.user.profile || {};
    }
    return userData?.profile || {};
  };

  const checkMentorConnections = async (mentorResponse) => {
    try {
      if (mentorResponse.status === 'fulfilled' && mentorResponse.value.success) {
        const acceptedMentors = mentorResponse.value.requests?.filter(
          req => req.status === 'accepted'
        ).length || 0;
        return Math.min((acceptedMentors / 3) * 100, 100);
      }
      return 0;
    } catch (error) {
      return 0;
    }
  };

  const calculateProfileCompletion = (profile) => {
    if (!profile) return 0;
    
    const completionCriteria = [
      { key: 'bio', weight: 25, check: (val) => val && val.trim().length > 10 },
      { key: 'education', weight: 25, check: (val) => val && val.trim().length > 0 },
      { key: 'experience', weight: 25, check: (val) => val && val.trim().length > 0 },
      { key: 'skills', weight: 25, check: (val) => val && val.length > 0 }
    ];

    let totalScore = 0;
    completionCriteria.forEach(criteria => {
      if (criteria.check(profile[criteria.key])) {
        totalScore += criteria.weight;
      }
    });

    return totalScore;
  };

  const calculateSkillsProgress = (skills) => {
    const skillsCount = skills.length;
    return Math.min((skillsCount / 5) * 100, 100);
  };

  const getOverallProgress = () => {
    const values = Object.values(progress);
    return Math.round(values.reduce((a, b) => a + b, 0) / values.length);
  };

  const getProgressColor = (percentage) => {
    if (percentage >= 80) return '#10b981';
    if (percentage >= 50) return '#f59e0b';
    return '#ef4444';
  };

  const getLevelInfo = (percentage) => {
    if (percentage >= 80) return { name: 'Advanced', color: '#10b981', icon: '🚀' };
    if (percentage >= 60) return { name: 'Intermediate', color: '#f59e0b', icon: '⭐' };
    if (percentage >= 40) return { name: 'Beginner', color: '#3b82f6', icon: '🌱' };
    return { name: 'Getting Started', color: '#6b7280', icon: '🎯' };
  };

  if (!user) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to view your progress.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="progress-container">
        <div className="container">
          <div className="loading">
            <div className="spinner"></div>
            Loading your progress...
          </div>
        </div>
      </div>
    );
  }

  const overallProgress = getOverallProgress();
  const levelInfo = getLevelInfo(overallProgress);

  return (
    <div className="progress-container">
      <div className="container">
        {/* Header */}
        <div className="progress-header">
          <div className="header-content">
            <div>
              <h1>📊 Your Career Progress</h1>
              <p>Track your career development journey</p>
            </div>
            <button 
              onClick={fetchProgress}
              className="btn btn-secondary refresh-btn"
              disabled={loading}
            >
              {loading ? '🔄 Updating...' : '🔄 Refresh'}
            </button>
          </div>
          {lastUpdated && (
            <div className="last-updated">
              Last updated: {lastUpdated.toLocaleTimeString()}
            </div>
          )}
        </div>

        {/* Welcome Section for New Users */}
        {overallProgress < 30 && (
          <div className="welcome-section">
            <div className="welcome-content">
              <div className="welcome-icon">🎯</div>
              <div className="welcome-text">
                <h3>Welcome to Your Career Journey!</h3>
                <p>Start by completing these key steps to unlock personalized career guidance and mentor matching.</p>
              </div>
            </div>
          </div>
        )}

        {/* Overall Progress Card */}
        <div className="overall-progress-card">
          <div className="progress-main">
            <div className="progress-circle">
              <div className="circle-bg">
                <div 
                  className="circle-progress"
                  style={{
                    background: `conic-gradient(${levelInfo.color} ${overallProgress * 3.6}deg, #e5e7eb 0deg)`
                  }}
                ></div>
                <div className="circle-content">
                  <span className="progress-percent">{overallProgress}%</span>
                  <span className="progress-label">Complete</span>
                </div>
              </div>
            </div>
            <div className="progress-info">
              <div className="level-badge" style={{ backgroundColor: levelInfo.color }}>
                {levelInfo.icon} {levelInfo.name}
              </div>
              <h3>Overall Progress</h3>
              <p>You're on your way to career success! Keep going to unlock more features.</p>
              
              <div className="progress-stats">
                <div className="stat">
                  <span className="stat-value">{progress.quizCompleted}%</span>
                  <span className="stat-label">Career Quiz</span>
                </div>
                <div className="stat">
                  <span className="stat-value">{progress.profileCompleted}%</span>
                  <span className="stat-label">Profile</span>
                </div>
                <div className="stat">
                  <span className="stat-value">{progress.mentorsConnected}%</span>
                  <span className="stat-label">Mentors</span>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Progress Steps */}
        <div className="progress-steps">
          <h3>Your Career Setup Checklist</h3>
          <div className="steps-grid">
            {/* Quiz Step */}
            <div className={`step-card ${progress.quizCompleted === 100 ? 'completed' : 'current'}`}>
              <div className="step-header">
                <div className="step-icon">🎯</div>
                <div className="step-title">
                  <h4>Career Assessment</h4>
                  <span className="step-status">
                    {progress.quizCompleted === 100 ? 'Completed' : 'Not Started'}
                  </span>
                </div>
                <div className="step-percentage">{progress.quizCompleted}%</div>
              </div>
              <p>Take our career quiz to discover your ideal career path and get personalized recommendations.</p>
              <div className="step-actions">
                {progress.quizCompleted === 100 ? (
                  <div className="completed-actions">
                    <span className="success-text">✅ Great job! Assessment complete</span>
                    <button 
                      onClick={() => window.location.href = '/quiz-results'}
                      className="btn btn-outline btn-small"
                    >
                      View Results
                    </button>
                  </div>
                ) : (
                  <button 
                    onClick={() => window.location.href = '/quiz'}
                    className="btn btn-primary btn-small"
                  >
                    Start Career Quiz
                  </button>
                )}
              </div>
            </div>

            {/* Profile Step */}
            <div className={`step-card ${progress.profileCompleted === 100 ? 'completed' : progress.quizCompleted === 100 ? 'current' : 'upcoming'}`}>
              <div className="step-header">
                <div className="step-icon">👤</div>
                <div className="step-title">
                  <h4>Complete Profile</h4>
                  <span className="step-status">
                    {progress.profileCompleted === 100 ? 'Completed' : `${progress.profileCompleted}% Complete`}
                  </span>
                </div>
                <div className="step-percentage">{progress.profileCompleted}%</div>
              </div>
              <p>Build your complete profile to get better career matches and mentor recommendations.</p>
              <div className="step-progress">
                <div className="progress-bar">
                  <div 
                    className="progress-fill" 
                    style={{ 
                      width: `${progress.profileCompleted}%`,
                      backgroundColor: getProgressColor(progress.profileCompleted)
                    }}
                  ></div>
                </div>
              </div>
              <div className="step-actions">
                <button 
                  onClick={() => window.location.href = '/profile'}
                  className="btn btn-secondary btn-small"
                >
                  {progress.profileCompleted === 100 ? 'Update Profile' : 'Complete Profile'}
                </button>
              </div>
            </div>

            {/* Mentors Step */}
            <div className={`step-card ${progress.mentorsConnected === 100 ? 'completed' : progress.profileCompleted >= 50 ? 'current' : 'upcoming'}`}>
              <div className="step-header">
                <div className="step-icon">👥</div>
                <div className="step-title">
                  <h4>Connect with Mentors</h4>
                  <span className="step-status">
                    {progress.mentorsConnected === 100 ? 'Connected' : 'Find Mentors'}
                  </span>
                </div>
                <div className="step-percentage">{progress.mentorsConnected}%</div>
              </div>
              <p>Connect with experienced professionals who can guide your career growth and development.</p>
              <div className="step-actions">
                <button 
                  onClick={() => window.location.href = '/mentors'}
                  className="btn btn-primary btn-small"
                >
                  {progress.mentorsConnected > 0 ? 'Find More Mentors' : 'Browse Mentors'}
                </button>
              </div>
            </div>

            {/* Skills Step */}
            <div className={`step-card ${progress.skillsAdded === 100 ? 'completed' : 'upcoming'}`}>
              <div className="step-header">
                <div className="step-icon">🛠️</div>
                <div className="step-title">
                  <h4>Develop Skills</h4>
                  <span className="step-status">
                    {progress.skillsAdded === 100 ? 'Skilled Up' : 'Add Skills'}
                  </span>
                </div>
                <div className="step-percentage">{progress.skillsAdded}%</div>
              </div>
              <p>Build the skills needed for your target careers through personalized learning paths.</p>
              <div className="step-actions">
                <button 
                  onClick={() => window.location.href = '/profile'}
                  className="btn btn-secondary btn-small"
                >
                  Manage Skills
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Quick Stats */}
        <div className="quick-stats">
          <h3>Your Progress at a Glance</h3>
          <div className="stats-grid">
            <div className="stat-card">
              <div className="stat-icon">🎯</div>
              <div className="stat-content">
                <div className="stat-value">{progress.quizCompleted}%</div>
                <div className="stat-label">Career Quiz</div>
                <div className="stat-desc">Discover your path</div>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">👤</div>
              <div className="stat-content">
                <div className="stat-value">{progress.profileCompleted}%</div>
                <div className="stat-label">Profile Complete</div>
                <div className="stat-desc">Build your presence</div>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">👥</div>
              <div className="stat-content">
                <div className="stat-value">{progress.mentorsConnected}%</div>
                <div className="stat-label">Mentors</div>
                <div className="stat-desc">Get guidance</div>
              </div>
            </div>
            <div className="stat-card">
              <div className="stat-icon">🛠️</div>
              <div className="stat-content">
                <div className="stat-value">{progress.skillsAdded}%</div>
                <div className="stat-label">Skills Added</div>
                <div className="stat-desc">Grow your abilities</div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Progress;
